" BDEF: Numbering configuration
" Early numbering (managed):
define behavior for Z_Travel {
  numbering managed;
  field ( numbering : managed ) TravelID;
}

" Late numbering (custom):
define behavior for Z_Document {
  numbering late;
  field ( numbering : late ) DocumentID;
}

" Behavior pool: late numbering implementation
METHOD late_numbering FOR NUMBERING
  IMPORTING entities FOR CREATE Document.
  LOOP AT entities INTO DATA(ls_entity).
    DATA(lv_fiscal_year) = ls_entity-%data-CreationDate+0(4).
    CALL FUNCTION 'NUMBER_GET_NEXT'
      EXPORTING nr_range_nr = '01' object = 'Z_DOC_NR'
      IMPORTING number = DATA(lv_seq).
    SET KEY FROM ls_entity-%key TO ls_entity-%pid
      ASSIGNING FIELD-SYMBOL(<fs_key>).
    <fs_key>-DocumentID = |{ lv_seq WIDTH = 6 ALPHA = IN }|.
  ENDLOOP.
ENDMETHOD.

