"""
  Authorization check in behavior pool
"""
CLASS zbp_rap_travel IMPLEMENTATION.

  METHOD get_instance_authorizations FOR AUTHORIZATION
    IMPORTING keys REQUEST requested_authorizations FOR Travel
    RESULT result.

    READ ENTITIES OF Z_Travel IN LOCAL MODE
      ENTITY Travel
      FROM VALUE #( FOR key IN keys ( TravelID = key-TravelID ) )
      RESULT DATA(lt_travel).

    LOOP AT lt_travel INTO DATA(ls_travel).
      " Check PFCG authorization for sales org
      AUTHORITY-CHECK OBJECT 'Z_TRV_AUTH'
        ID 'ACTVT' FIELD '03'
        ID 'ZTRVORG' FIELD ls_travel-SalesOrganization.

      IF sy-subrc = 0.
        result = VALUE #( BASE result (
          %tky = ls_travel-%tky
          %create = if_abap_behv=>mk-on
          %update = if_abap_behv=>mk-on
          %delete = if_abap_behv=>mk-on
          %action-acceptTravel = if_abap_behv=>mk-on
        ) ).
      ELSE.
        result = VALUE #( BASE result (
          %tky = ls_travel-%tky
          %create = if_abap_behv=>mk-off
          %update = if_abap_behv=>mk-off
          %delete = if_abap_behv=>mk-off
        ) ).
      ENDIF.
    ENDLOOP.

  ENDMETHOD.

ENDCLASS.

